#include <string>
#include <set>
#include <vector>

using namespace std;

vector<string> solve(string s) {
    set<string> used;
    vector<string> segments;
    string current;
    int i = 0;
    int n = s.length();
    while (i < n) {
        current += s[i];
        while (used.find(current) != used.end()) {
            if (i + 1 >= n) break;
            i++;
            current += s[i];
        }
        if (used.find(current) == used.end()) {
            used.insert(current);
            segments.push_back(current);
            current.clear();
        }
        i++;
    }
    return segments;
}
